export async function fetchSmartQuote({text:e="",images:r=[]}={}){const o=typeof e=="string"?e:"",a=Array.isArray(r)?r:[];if(!o.trim()&&a.length===0)throw new Error("SmartQuote requires extracted text or images");const t=await fetch("https://trueprice-smartquote.glane0303.workers.dev",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({text:o,images:a})});if(!t.ok){const s=await t.text();throw new Error(`SmartQuote failed: ${t.status} ${s}`)}return await t.json()}
